import {
  safeLstatSync,
  safeUnlinkSync,
  safeRmSync,
} from '@/shared/neverthrow/fs';
import { fsErr } from '@/shared/neverthrow/fs';
import { ok } from '@agentcash/neverthrow';

export function rmForce(surface: string, target: string) {
  const statResult = safeLstatSync(surface, target);
  if (statResult.isOk()) {
    const stat = statResult.value;
    if (!stat) {
      return fsErr(surface, {
        cause: 'file_not_readable',
        message: `Failed to stat ${target}`,
      });
    }

    if (stat.isSymbolicLink()) {
      const unlinkResult = safeUnlinkSync(surface, target);
      if (unlinkResult.isErr()) {
        return unlinkResult;
      }

      return ok(undefined);
    }
  }

  if (statResult.isErr()) {
    if (statResult.error.cause === 'file_not_found') {
      return ok(undefined);
    }

    return statResult;
  }

  const rmResult = safeRmSync(surface, target, {
    recursive: true,
    force: true,
  });
  if (rmResult.isErr()) {
    return rmResult;
  }

  return ok(undefined);
}
